import React from "react";
import { useNavigate } from "react-router-dom";
import "../styles/Signup.css";
import illustration from "../assets/signup-illustration.png";
// OR video
// import video from "../assets/ai-therapy.mp4";

function Signup() {
  const navigate = useNavigate();

  return (
    <div className="signup-wrapper">
      <div className="signup-container">
        
        {/* LEFT SIDE – SIGNUP CARD */}
        <div className="signup-card">
          <h2>Create Account</h2>
          <p>Your AI therapist is waiting for you</p>

          <div className="signup-form">
            <input type="text" placeholder="Full Name" />
            <input type="email" placeholder="Email" />

            <select>
              <option>Select Gender</option>
              <option>Male</option>
              <option>Female</option>
              <option>Other</option>
            </select>

            <input type="date" />

            <input type="text" placeholder="Username" />
            <input type="password" placeholder="Password" />

            <input type="tel" placeholder="Phone Number" />
            <input type="tel" placeholder="Alternative Phone Number" />

            <button className="signup-btn">Sign Up</button>
          </div>

          <div className="login-link">
            Already have an account?{" "}
            <a onClick={() => navigate("/")}>Login</a>
          </div>
        </div>

        {/* RIGHT SIDE – ILLUSTRATION / VIDEO */}
        <div className="signup-illustration">
          {/* IMAGE */}
          <img src={illustration} alt="AI Therapist" />

          {/* VIDEO (use this instead if you want video)
          <video autoPlay loop muted>
            <source src={video} type="video/mp4" />
          </video>
          */}
        </div>

      </div>
    </div>
  );
}

export default Signup;
